public class Main {
    public static void main(String[] args) {

        String studentName = "Sneha Patel";
        int    score       = 83;

        // Multi-branch grade assignment
        String grade, feedback;

        if (score >= 90) {
            grade    = "A";
            feedback = "Outstanding performance!";
        } else if (score >= 80) {
            grade    = "B";
            feedback = "Great work, keep it up!";
        } else if (score >= 70) {
            grade    = "C";
            feedback = "Good effort, room to improve.";
        } else if (score >= 60) {
            grade    = "D";
            feedback = "Needs more practice.";
        } else {
            grade    = "F";
            feedback = "Please seek extra help.";
        }

        System.out.println("Student  : " + studentName);
        System.out.println("Score    : " + score + "/100");
        System.out.println("Grade    : " + grade);
        System.out.println("Feedback : " + feedback);

        // Ternary operator
        String result = score >= 50 ? "PASS" : "FAIL";
        System.out.println("Result   : " + result);
    }
}

