exercise.solutionCode:
public class Main {
    public static void main(String[] args) {
        int age         = 25;
        int ticketPrice = 0;

        if (age < 5) {
            ticketPrice = 0;
        } else if (age <= 12) {
            ticketPrice = 100;
        } else if (age <= 17) {
            ticketPrice = 150;
        } else if (age <= 59) {
            ticketPrice = 200;
        } else {
            ticketPrice = 120;
        }

        System.out.println("Age: " + age);
        System.out.println("Ticket Price: Rs " + ticketPrice);
    }
}
